    { id: 60, difficulty: "dificil", question: { pt: "Como se define um 'super-espalhador' (superspreader)?", es: "¿Superspreader?" }, answer: { pt: "Indivíduo que transmite o patógeno para um número desproporcionalmente alto de pessoas.", es: "Individuo que infecta a muchos." } }
